{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/SpacingAroundColonInAnnotationTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonInAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given annotation use-site target with correct spacing (no spaces) then no lint violations`() {
        val code =
            """
            @file:JvmName("Foo")
            @set:[Inject VisibleForTesting]
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            fun @receiver:Fancy String.myExtension() { }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given annotation use-site target with space before colon then lint violation`() {
        val code =
            """
            @file :JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 6, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation use-site target with space after colon then lint violation`() {
        val code =
            """
            @file: JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 7, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation use-site target with spaces before and after colon then lint violations`() {
        val code =
            """
            @file : JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing before \":\""),
                LintViolation(1, 7, "Unexpected spacing after \":\""),
            )
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation entry with space before colon then lint violation`() {
        val code =
            """
            @set :[Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        val formattedCode =
            """
            @set:[Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 5, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation entry with space after colon then lint violation`() {
        val code =
            """
            @set: [Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        val formattedCode =
            """
            @set:[Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 6, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation entry with spaces before and after colon then lint violations`() {
        val code =
            """
            @set : [Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        val formattedCode =
            """
            @set:[Inject VisibleForTesting]
            public var collaborator: Collaborator
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 5, "Unexpected spacing before \":\""),
                LintViolation(1, 6, "Unexpected spacing after \":\""),
            )
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given multiple annotation use-site targets with various spacing issues then lint violations`() {
        val code =
            """
            @file :JvmName("Foo")
            class Example(@field :Ann val foo: String, @get: Ann val bar: String, @param : Baz val baz: String)
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String, @param:Baz val baz: String)
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing before \":\""),
                LintViolation(2, 22, "Unexpected spacing before \":\""),
                LintViolation(2, 50, "Unexpected spacing after \":\""),
                LintViolation(2, 78, "Unexpected spacing before \":\""),
                LintViolation(2, 79, "Unexpected spacing after \":\""),
            )
            .isFormattedAs(formattedCode)
    }
}
